#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    char line[256];
    int freq[26] = {0};

    fgets(line, sizeof(line), stdin);

    for (int i = 0; line[i] != '\0'; i++) {
        char c = tolower(line[i]);
        if (c >= 'a' && c <= 'z') {
            freq[c - 'a']++;
        }
    }

    for (int i = 0; i < 26; i++) {
        if (freq[i] > 0) {
            printf("%c %d\n", 'a' + i, freq[i]);
        }
    }

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    char line[256];
    fgets(line, sizeof(line), stdin);

    // Extract only alphabetic characters in lowercase
    char cleaned[256];
    int j = 0;
    for (int i = 0; line[i] != '\0'; i++) {
        if (isalpha(line[i])) {
            cleaned[j++] = tolower(line[i]);
        }
    }
    cleaned[j] = '\0';

    // Check if palindrome
    int is_palindrome = 1;
    for (int i = 0; i < j / 2; i++) {
        if (cleaned[i] != cleaned[j - 1 - i]) {
            is_palindrome = 0;
            break;
        }
    }

    printf("%s\n", is_palindrome ? "yes" : "no");

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    char line[256];
    fgets(line, sizeof(line), stdin);

    char longest[256] = "";
    int max_len = 0;
    char current[256];
    int current_len = 0;

    for (int i = 0; line[i] != '\0'; i++) {
        if (isalpha(line[i])) {
            current[current_len++] = line[i];
        } else {
            if (current_len > max_len) {
                current_len = 0;
                for (int j = 0; j < current_len; j++) {
                    longest[j] = current[j];
                }
                longest[current_len] = '\0';
                max_len = current_len;
            }
            current_len = 0;
        }
    }

    // Check the last word
    if (current_len > max_len) {
        for (int j = 0; j < current_len; j++) {
            longest[j] = current[j];
        }
        longest[current_len] = '\0';
        max_len = current_len;
    }

    printf("%s\n", longest);

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    char line[256];
    fgets(line, sizeof(line), stdin);

    int vowels = 0, consonants = 0;

    for (int i = 0; line[i] != '\0'; i++) {
        char c = tolower(line[i]);
        if (isalpha(line[i])) {
            if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
                vowels++;
            } else {
                consonants++;
            }
        }
    }

    printf("vowels %d\n", vowels);
    printf("consonants %d\n", consonants);

    return 0;
}

