    int seen[256] = {0};

    for (int i = 0; line[i] != '\0'; i++) {
        unsigned char c = (unsigned char)line[i];
        if (!seen[c]) {
            seen[c] = 1;
            printf("%c", c);
        }
    }
    printf("\n");

    return 0;
}

#include <stdio.h>
#include <string.h>

int main() {
    char line[256];
    fgets(line, sizeof(line), stdin);

    int depth = 0;
    int valid = 1;

    for (int i = 0; line[i] != '\0' && valid; i++) {
        char c = line[i];
        if (c == '(' || c == '[' || c == '{') {
            depth++;
        } else if (c == ')' || c == ']' || c == '}') {
            depth--;
            if (depth < 0) {
                valid = 0;
            }
        }
    }

    if (depth != 0) {
        valid = 0;
    }

    printf("%s\n", valid ? "yes" : "no");

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    int n;
    scanf("%d\n", &n);

    char line[256];
    fgets(line, sizeof(line), stdin);

    int count = 0;
    int word_len = 0;

    for (int i = 0; line[i] != '\0'; i++) {
        if (isalpha(line[i])) {
            word_len++;
        } else {
            if (word_len > n) {
                count++;
            }
            word_len = 0;
        }
    }

    // Check last word
    if (word_len > n) {
        count++;
    }

    printf("%d\n", count);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int n;
    scanf("%d", &n);

    int *arr = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    int k;
    scanf("%d", &k);
    k = k % n;  // Handle k > n

    // Create result array
    int *result = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        result[(i + k) % n] = arr[i];
    }

    for (int i = 0; i < n; i++) {
        printf("%d", result[i]);
        if (i < n - 1) printf(" ");
    }
    printf("\n");

    free(arr);
    free(result);

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    long long expected_sum = (long long)(n + 1) * (n + 2) / 2;
    long long actual_sum = 0;

    for (int i = 0; i < n; i++) {
        int num;
        scanf("%d", &num);
        actual_sum += num;
    }

    printf("%lld\n", expected_sum - actual_sum);

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    char line1[256], line2[256];
    fgets(line1, sizeof(line1), stdin);
    fgets(line2, sizeof(line2), stdin);

    int freq1[26] = {0}, freq2[26] = {0};

    for (int i = 0; line1[i] != '\0'; i++) {
        char c = tolower(line1[i]);
        if (isalpha(c)) {
            freq1[c - 'a']++;
        }
    }

    for (int i = 0; line2[i] != '\0'; i++) {
        char c = tolower(line2[i]);
        if (isalpha(c)) {
            freq2[c - 'a']++;
        }
    }

    int is_anagram = 1;
    for (int i = 0; i < 26; i++) {
        if (freq1[i] != freq2[i]) {
            is_anagram = 0;
            break;
        }
    }

    printf("%s\n", is_anagram ? "yes" : "no");

    return 0;
}
